// Skip ranking: pass articles through with default score
const articles = $('Input').all().map(i => i.json);
console.log('Ranking SKIPPED: ' + articles.length + ' articles passed through with score=50');
return articles.map(a => ({ json: { ...a, score: 50, score_reason: 'Ranking skipped by user', score_breakdown: null } }));

// === PRE-FILTER v2 - TF-IDF ameliore ===
const articles = $input.all().map(i => i.json);
const question = (articles[0] && articles[0].question) || '';
const prefilterEnabled = articles[0] && articles[0].prefilter_enabled !== undefined ? articles[0].prefilter_enabled : true;
const prefilterCount = (articles[0] && parseInt(articles[0].prefilter_count)) || 300;

if (!prefilterEnabled) {
  console.log('Pre-filter: DESACTIVE - ' + articles.length + ' articles passes sans filtre');
  return articles.map(a => ({ json: a }));
}

const stopWords = new Set(['the','a','an','and','or','of','in','to','for','with','on','at','by','from','is','are','was','were','be','been','being','that','this','it','its','as','but','not','no','do','does','did','has','have','had','will','would','can','could','should','may','might','shall','about','into','through','during','before','after','above','below','between','under','over','each','every','all','both','few','more','most','other','some','such','than','too','very','just','also','how','what','which','who','where','when','why','our','their','your','we','they','them','these','those','only','own','same','then','there','here','study','studies','results','method','methods','conclusion','background','objective','objectives','aim','aims','purpose','review','research','analysis','data','based','using','used','among','associated','effect','effects','impact','factors','findings','evidence','approach','compared','significant','compared','group','groups']);

const getKeywords = (text) => {
  return (text || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(w => w.length > 2 && !stopWords.has(w));
};

const questionKeywords = getKeywords(question);
const questionSet = new Set(questionKeywords);

if (questionKeywords.length === 0 || articles.length <= prefilterCount) {
  console.log('Pre-filter: pas necessaire (' + articles.length + ' articles <= seuil ' + prefilterCount + ')');
  return articles.map(a => ({ json: a }));
}

const scored = articles.map(a => {
  const text = ((a.title || '') + ' ' + (a.abstract || '')).toLowerCase();
  const articleWords = new Set(getKeywords(text));
  let matchCount = 0;
  for (const w of questionSet) {
    if (articleWords.has(w)) matchCount++;
  }
  return { article: a, score: matchCount / questionKeywords.length };
});

scored.sort((a, b) => b.score - a.score);
const kept = scored.slice(0, prefilterCount).map(s => s.article);
console.log('Pre-filter v2: ' + articles.length + ' -> ' + kept.length + ' articles');
return kept.map(a => ({ json: a }));

// === RANKING v4 - Criteres explicites + prompt simplifie ===
const items = $input.all();
const articles = items.map(i => i.json);
// (A3) Reglages IA personnalises injectes par l'UI dans articles[0]._ai_settings
const aiSettings = (articles[0] && articles[0]._ai_settings) || {};
const strictness = (typeof aiSettings.strictness === 'number') ? aiSettings.strictness : 50;
const customRules = (aiSettings.custom_rules || '').toString().trim();
let strictnessGuidance = '';
if (strictness <= 25) {
  strictnessGuidance = '

TONE: Be GENEROUS with scoring. Articles loosely related to the question still deserve scores in the 40-60 range.';
} else if (strictness >= 75) {
  strictnessGuidance = '

TONE: Be STRICT with scoring. Only highly relevant articles deserve scores >70. Be sparing with high scores.';
}
const customRulesBlock = customRules
  ? '

USER-DEFINED RULES (apply these):
' + customRules
  : '';
const BATCH_SIZE = 3;
const question = (articles[0] && articles[0].question) || '';
const criteria = (articles[0] && articles[0].criteria) || '';
const batches = [];

function sanitize(text) {
  return (text || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim();
}

for (let i = 0; i < articles.length; i += BATCH_SIZE) {
  const batch = articles.slice(i, i + BATCH_SIZE);
  const articleList = batch.map((a, j) => {
    const title = sanitize(a.title || 'No title').substring(0, 120);
    const abstract = sanitize(a.abstract || 'No abstract').substring(0, 300);
    return '[' + j + '] TITLE: ' + title + '
ABSTRACT: ' + abstract;
  }).join('

');

  const prompt = `You are a systematic review screener. Rate each article 0-100 for relevance to the research question.

RESEARCH QUESTION:
${sanitize(question).substring(0, 500)}

INCLUSION/EXCLUSION CRITERIA:
${sanitize(criteria).substring(0, 500)}

=== ARTICLES TO RATE ===
${articleList}

=== SCORING RUBRIC (each 0-25, total 0-100) ===

1. TOPIC RELEVANCE (0-25): Does the article address the EXACT topic of the research question?
   - 25 = directly about the research question topic
   - 15 = related topic, partial overlap
   - 5 = tangentially related
   - 0 = unrelated topic

2. POPULATION MATCH (0-25): Does the studied population match the inclusion criteria?
   - 25 = exact match (e.g. correct age range, geography, condition)
   - 15 = partial match (e.g. broader population including target)
   - 5 = loosely related population
   - 0 = wrong population (e.g. animal study when humans required)

3. METHODOLOGY (0-25): Is the study type appropriate?
   - 25 = empirical, peer-reviewed, adequate sample (RCT, cohort, large survey)
   - 15 = empirical but small sample or non-peer-reviewed
   - 5 = case report, opinion, editorial, narrative review
   - 0 = no methodology described / not a study

4. PERIOD & CONTEXT (0-25): Date range and geographic/cultural context fit?
   - 25 = within specified period AND relevant region
   - 15 = within period OR relevant region (one missing)
   - 5 = older or different region but transferable
   - 0 = clearly outside period and context

=== OUTPUT FORMAT ===
Return ONLY a JSON object with this exact structure (no markdown, no explanation):
{"scores":[{"index":0,"topic":20,"population":15,"methodology":15,"context":10,"score":60,"reason":"brief justification"}]}

Provide one entry per article, indexes 0 to ${batch.length - 1}. Use the full 0-100 range to discriminate.${strictnessGuidance}${customRulesBlock}`;

  batches.push({ json: { prompt, batchIndex: Math.floor(i / BATCH_SIZE), batchSize: batch.length } });
}

console.log('Ranking v4: ' + articles.length + ' articles -> ' + batches.length + ' batches de ' + BATCH_SIZE);
return batches;

// === EXPAND v4 - Parser JSON robuste (tolere texte autour) ===
const responses = $input.all();
const originalItems = $('Pre-Filter Keywords').all();
const articles = originalItems.map(i => i.json);
const BATCH_SIZE = 3;

// Extrait le JSON {...} du texte meme s'il y a du texte autour ou des backticks
function extractJson(text) {
  if (!text) return null;
  // Retire les blocs markdown ```json ... ```
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '');
  // Cherche le premier { qui ouvre un JSON valide jusqu'au } qui le ferme
  const start = text.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < text.length; i++) {
    const c = text[i];
    if (escape) { escape = false; continue; }
    if (c === '\\') { escape = true; continue; }
    if (c === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (c === '{') depth++;
    else if (c === '}') {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(text.substring(start, i + 1)); } catch(e) { return null; }
      }
    }
  }
  return null;
}

const results = [];
let scoreSum = 0;
let okBatches = 0;
let failedBatches = 0;
const diagnostics = [];

for (let r = 0; r < responses.length; r++) {
  const resp = responses[r].json || {};
  let scoreMap = {};
  let batchOk = false;

  if (resp.response) {
    const parsed = extractJson(resp.response);
    if (parsed && Array.isArray(parsed.scores)) {
      parsed.scores.forEach((s, autoIdx) => {
        // (Fix 2026-05-19) Tolerer index manquant : assumer ordre sequentiel du batch.
        const idx = (s.index !== undefined) ? s.index : autoIdx;
        // Score peut etre fourni ou calcule depuis breakdown
        let score;
        if (s.score !== undefined) {
          score = parseInt(s.score) || 0;
        } else {
          score = (parseInt(s.topic) || 0) + (parseInt(s.population) || 0) + (parseInt(s.methodology) || 0) + (parseInt(s.context) || 0);
        }
        score = Math.max(0, Math.min(100, score));
        const breakdown = (s.topic !== undefined) ? {
          topic: parseInt(s.topic) || 0,
          population: parseInt(s.population) || 0,
          methodology: parseInt(s.methodology) || 0,
          context: parseInt(s.context) || 0
        } : (s.breakdown || null);
        scoreMap[idx] = { score, reason: s.reason || '', breakdown };
      });
      batchOk = Object.keys(scoreMap).length > 0;
    } else {
      // Diagnostic : log les 200 premiers chars de la reponse
      diagnostics.push('Batch ' + r + ' parse failed - response starts: ' + (resp.response || '').substring(0, 200));
    }
  } else if (resp.error) {
    diagnostics.push('Batch ' + r + ' API error: ' + (resp.error.message || resp.error).toString().substring(0, 100));
  } else {
    diagnostics.push('Batch ' + r + ' empty response');
  }

  if (batchOk) okBatches++; else failedBatches++;

  const start = r * BATCH_SIZE;
  const end = Math.min(start + BATCH_SIZE, articles.length);
  for (let i = start; i < end; i++) {
    const localIdx = i - start;
    const data = scoreMap[localIdx] || { score: 50, reason: batchOk ? 'Index missing in response' : 'Batch failed - default score', breakdown: null };
    scoreSum += data.score;
    results.push({
      json: {
        ...articles[i],
        score: data.score,
        score_reason: data.reason,
        score_breakdown: data.breakdown
      }
    });
  }
}

const avg = results.length > 0 ? Math.round(scoreSum / results.length) : 0;
console.log('=== Ranking v4 complete ===');
console.log('Articles: ' + results.length + ' | Batches OK: ' + okBatches + ' | Batches KO: ' + failedBatches);
console.log('Score moyen: ' + avg + '/100');
if (diagnostics.length > 0) {
  console.log('--- Diagnostics (premiers echecs) ---');
  diagnostics.slice(0, 3).forEach(d => console.log(d));
}
return results;
